module top_module(
    input  VPWR,
    input  UDP_IN,
    input  CLK,
    output UDP_OUT
);reg unused_pwrgood;

    always @(posedge CLK) begin
        if (UDP_IN) begin
            unused_pwrgood <= 0;
        end else begin
            unused_pwrgood <= VPWR;
        end
    end

    assign UDP_OUT = unused_pwrgood;

endmodule
